ounded px-3 py-1 mr-3 text-sm font-medium\" @click=\"changeStatus()\">Submit</a>\n                            <a href=\"#\" class=\"btn btn-reset bg-gray-100 text-gray-700 border rounded px-3 py-1 mr-3 text-sm font-medium\" @click=\"resetform()\">Reset</a>\n                        </div>\n                    </div>\n                </div>\n            </div>\n        </div>  \n    </div>\n</template>\n\n<script>\n    export default{\n        props:['url'],\n        data(){\n            return{\n                academic_years:[],\n                success:null,\n                errors:[],\n                show:0,\n                academic_year_id:'',\n            }\n        },\n\n        methods:\n        {\n            getData()\n            {\n                axios.get('/admin/academic/list').then(response => {\n                    this.academic_years     = response.data.academic_years;\n                    this.academic_year_id   = response.data.academic_year_id;\n                    //console.log(this.academic_years);\n                });\n            },\n\n            showTab()\n            {\n                this.show = 1;\n            },\n\n            closeModal()\n            {\n                this.show = 0;\n                window.location.reload();\n            },\n\n            resetform()\n            {\n                this.getData();\n            },\n\n            changeStatus()\n            {\n                this.errors=[];\n                this.success=null;\n\n                let formData=new FormData(); \n\n                formData.append('academic_year_id',this.academic_year_id);\n\n                axios.post('/admin/academic/updateStatus',formData,{headers: {'Content-Type': 'multipart/form-data'}}).then(response => {     \n                    this.success = response.data.success;\n                    this.closeModal();\n                }).catch(error => {\n                    this.errors = error.response.data.errors;\n                });\n            },\n\n            deleteAcademic(id)\n            {\n                var thisswal = this;\n                swal({\n                    title: 'Are you sure',\n                    text: 'Do you want to delete this Academic Year ?',\n                    icon: \"info\",\n                    buttons: [\n                        'No',\n                        'Yes'\n                    ],\n                    dangerMode: true,\n                }).then(function(isConfirm) {\n                    if (isConfirm) \n                    {\n                        axios.get(thisswal.url+'/admin/academic/delete/'+ id).then(response => {\n                            thisswal.success = response.data.success;\n                            window.location.reload();\n                        }); \n                    }\n                    else \n                    {\n                        swal(\"Cancelled\");\n                    }\n                });\n            },\n        },\n\n        created()\n        {\n            this.getData();\n        }\n    }\n</script>\n\n<style scoped>\n    .modal-mask {\n        position: fixed;\n        z-index: 9998;\n        top: 0;\n        left: 0;\n        width: 100%;\n        height: 100%;\n        background-color: rgba(0, 0, 0, .5);\n        display: table;\n        transition: opacity .3s ease;\n    }\n\n    .modal-wrapper {\n        display: table-cell;\n        vertical-align: middle;\n        overflow:auto;\n    }\n\n    .modal-container-new {\n        margin: 0px auto;\n        /*padding: 20px 30px;*/\n        background-color: #fff;\n        border-radius: 2px;\n        box-shadow: 0 2px 8px rgba(0, 0, 0, .33);\n        transition: all .3s ease;\n        height: 500px;\n        overflow:auto;\n    }\n\n    .modal-container {\n        margin: 0px auto;\n        /*padding: 20px 30px;*/\n        background-color: #fff;\n        border-radius: 2px;\n        box-shadow: 0 2px 8px rgba(0, 0, 0, .33);\n        transition: all .3s ease